def extract_mandatory_requirements(text):
    requirement_phrases = set()
    sentences = text.split(". ")

    for sentence in sentences:
        words = sentence.split()

        if "shall" in words or "must" in words:
            requirement_phrase = ""
            in_quote = False
            current_phrase = ""

            for word in words:
                if word in ['"', "'"]:
                    in_quote = not in_quote
                elif not in_quote:
                    current_phrase += " " + word
                else:
                    requirement_phrase += " " + word

            requirement_phrase = requirement_phrase.strip()

            # Check for quotes around the phrase
            if requirement_phrase.startswith('"') and requirement_phrase.endswith('"'):
                requirement_phrase = requirement_phrase[1:-1]
            # Check for single quotes around the phrase
            elif requirement_phrase.startswith("'") and requirement_phrase.endswith("'"):
                requirement_phrase = requirement_phrase[1:-1]

            requirement_phrases.add(requirement_phrase)

    return list(requirement_phrases)
